1	import { db } from '../db/db';
2	import type { SiteConfig, User } from '../types';
3	import { auditService } from './auditService';
4	import { assertManagerOrAdmin, assertSiteScope } from './rbacService';
5	
6	const DEFAULT_CONFIG: Omit<SiteConfig, 'siteId'> = {
7	  tempLeaveMaxCount: 1,
8	  tempLeaveMaxMinutes: 15,
9	  anomalyHeartbeatTimeoutMin: 30,
10	  noShowGraceMinutes: 10,
11	  ratePerMinute: 0.5
12	};
13	
14	const configCache = new Map<number, SiteConfig>();
15	
16	function buildConfig(siteId: number, partial: Partial<SiteConfig>): SiteConfig {
17	  return {
18	    siteId,
19	    tempLeaveMaxCount: partial.tempLeaveMaxCount ?? DEFAULT_CONFIG.tempLeaveMaxCount,
20	    tempLeaveMaxMinutes: partial.tempLeaveMaxMinutes ?? DEFAULT_CONFIG.tempLeaveMaxMinutes,
21	    anomalyHeartbeatTimeoutMin:
22	      partial.anomalyHeartbeatTimeoutMin ?? DEFAULT_CONFIG.anomalyHeartbeatTimeoutMin,
23	    noShowGraceMinutes: partial.noShowGraceMinutes ?? DEFAULT_CONFIG.noShowGraceMinutes,
24	    ratePerMinute: partial.ratePerMinute ?? DEFAULT_CONFIG.ratePerMinute
25	  };
26	}
27	
28	/**
29	 * Synchronous read from in-memory cache. The cache is populated by:
30	 *  - `loadSiteConfig()` at app boot (reads from IndexedDB)
31	 *  - `saveSiteConfig()` on every write (writes IndexedDB first, then updates cache)
32	 *
33	 * If the cache is cold (before boot hydration), falls back to defaults.
34	 * This is intentional: callers that need guaranteed fresh data should
35	 * await `loadSiteConfig()` first.
36	 */
37	function getSiteConfig(siteId: number): SiteConfig {
38	  const cached = configCache.get(siteId);
39	  if (cached) return cached;
40	  return { siteId, ...DEFAULT_CONFIG };
41	}
42	
43	/**
44	 * Async IndexedDB-first load. Called at app boot and whenever the
45	 * authoritative value is needed after a potential external change.
46	 * Populates the in-memory cache so subsequent sync reads are fast.
47	 */
48	async function loadSiteConfig(siteId: number): Promise<SiteConfig> {
49	  const stored = await db.siteConfigs.get(siteId).catch(() => undefined);
50	  if (stored) {
51	    const config = buildConfig(siteId, stored);
52	    configCache.set(siteId, config);
53	    return config;
54	  }
55	  const fallback = { siteId, ...DEFAULT_CONFIG };
56	  configCache.set(siteId, fallback);
57	  return fallback;
58	}
59	
60	/**
61	 * Write to IndexedDB (authoritative), then update the in-memory cache.
62	 * Also mirrors to localStorage for backward compat with any stale readers.
63	 */
64	async function saveSiteConfig(config: SiteConfig, actor?: User): Promise<void> {
65	  if (actor) {
66	    assertManagerOrAdmin(actor);
67	    assertSiteScope(actor, config.siteId);
68	  }
69	  await db.siteConfigs.put({ ...config, id: config.siteId });
70	  configCache.set(config.siteId, config);
71	  localStorage.setItem(`cb_site_config_${config.siteId}`, JSON.stringify(config));
72	  if (actor) {
73	    await auditService.log(actor, 'PRICING_UPDATED', 'SiteConfig', config.siteId, {
74	      ratePerMinute: config.ratePerMinute
75	    });
76	  }
77	}
78	
79	export const siteConfigService = {
80	  getSiteConfig,
81	  loadSiteConfig,
82	  saveSiteConfig
83	};
84	
