1	import { useMemo, useState } from 'react';
2	import { useLiveQuery } from 'dexie-react-hooks';
3	import FieldMapper from '../components/import/FieldMapper';
4	import { db } from '../db/db';
5	import { useAuth } from '../hooks/useAuth';
6	import { importService, type ImportType } from '../services/importService';
7	
8	export default function ImportPage() {
9	  const { currentUser, encryptionKey } = useAuth();
10	  const [type, setType] = useState<ImportType>('reservations');
11	  const [file, setFile] = useState<File | null>(null);
12	  const [headers, setHeaders] = useState<string[]>([]);
13	  const [fieldMap, setFieldMap] = useState<Record<string, string>>({});
14	  const [summary, setSummary] = useState<{
15	    totalRows: number;
16	    validRows: number;
17	    invalidRows: number;
18	    rows: Array<{ rowIndex: number; errorCode?: string }>;
19	  } | null>(null);
20	  const [error, setError] = useState<string | null>(null);
21	  const [busy, setBusy] = useState(false);
22	
23	  const history = useLiveQuery(async () => {
24	    if (!currentUser) {
25	      return [];
26	    }
27	    if (currentUser.role === 'SystemAdministrator') {
28	      return db.importBatches.orderBy('createdAt').reverse().toArray();
29	    }
30	    return db.importBatches
31	      .where('siteId')
32	      .equals(currentUser.siteId as number)
33	      .reverse()
34	      .sortBy('createdAt');
35	  }, [currentUser]);
36	
37	  const requiredFields = useMemo(() => importService.REQUIRED_FIELDS[type], [type]);
38	
39	  if (!currentUser) {
40	    return null;
41	  }
42	
43	  const missingRequired = requiredFields.filter(
44	    (field) => !Object.values(fieldMap).includes(field)
45	  );
46	
47	  return (
48	    <section className="card">
49	      <h1>Bulk Import</h1>
50	
51	      {!encryptionKey && (type === 'reservations' || type === 'orders') ? (
52	        <p className="error">
53	          Encryption key not available. Please re-authenticate to unlock encrypted data before importing {type}.
54	        </p>
55	      ) : null}
56	
57	      <h2>Step 1 - Template & Upload</h2>
58	      <div className="create-user-form">
59	        <select
60	          value={type}
61	          onChange={(event) => {
62	            const next = event.target.value as ImportType;
63	            setType(next);
64	            setFile(null);
65	            setHeaders([]);
66	            setFieldMap({});
67	            setSummary(null);
68	          }}
69	        >
70	          <option value="reservations">reservations</option>
71	          <option value="orders">orders</option>
72	          <option value="sessions">sessions</option>
73	        </select>
74	        <button className="button ghost" onClick={() => importService.downloadTemplate(type)}>
75	          Download Template
76	        </button>
77	        <input
78	          type="file"
79	          accept=".csv,.xlsx"
80	          onChange={async (event) => {
81	            const nextFile = event.target.files?.[0] ?? null;
82	            setFile(nextFile);
83	            setSummary(null);
84	            if (nextFile) {
85	              const preview = await importService.validateFile(
86	                nextFile,
87	                type,
88	                importService.autoMapFields([], type),
89	                currentUser
90	              );
91	              setHeaders(preview.headers);
92	              setFieldMap(importService.autoMapFields(preview.headers, type));
93	            }
94	          }}
95	        />
96	      </div>
97	
98	      {headers.length > 0 ? (
99	        <>
100	          <h2>Step 2 - Field Mapping</h2>
101	          <FieldMapper
102	            headers={headers}
103	            requiredFields={requiredFields}
104	            fieldMap={fieldMap}
105	            onChange={setFieldMap}
106	          />
107	          {missingRequired.length > 0 ? (
108	            <p className="error">Missing required mappings: {missingRequired.join(', ')}</p>
109	          ) : null}
110	          <button
111	            className="button ghost"
112	            disabled={!file || missingRequired.length > 0}
113	            onClick={async () => {
114	              if (!file) {
115	                return;
116	              }
117	              const result = await importService.validateFile(file, type, fieldMap, currentUser);
118	              setSummary({
119	                totalRows: result.totalRows,
120	                validRows: result.validRows,
121	                invalidRows: result.invalidRows,
122	                rows: result.rows.map((row) => ({ rowIndex: row.rowIndex, errorCode: row.errorCode }))
123	              });
124	            }}
125	          >
126	            Validate
127	          </button>
128	        </>
129	      ) : null}
130	
131	      {summary ? (
132	        <>
133	          <h2>Step 3 - Review & Import</h2>
134	          <p>
135	            Rows found: {summary.totalRows}, valid: {summary.validRows}, invalid: {summary.invalidRows}
136	          </p>
137	          {summary.invalidRows > 0 ? (
138	            <ul>
139	              {summary.rows
140	                .filter((row) => row.errorCode)
141	                .map((row) => (
142	                  <li key={row.rowIndex}>
143	                    Row {row.rowIndex}: {row.errorCode}
144	                  </li>
145	                ))}
146	            </ul>
147	          ) : null}
148	          <button
149	            className="button primary"
150	            disabled={!file || summary.invalidRows > 0 || missingRequired.length > 0 || busy || (!encryptionKey && (type === 'reservations' || type === 'orders'))}
151	            onClick={async () => {
152	              if (!file) {
153	                return;
154	              }
155	              setError(null);
156	              setBusy(true);
157	              try {
158	                await importService.startImport(file, type, fieldMap, currentUser, encryptionKey ?? undefined);
159	              } catch (importError) {
160	                if (importError instanceof Error) {
161	                  setError(importError.message);
162	                }
163	              } finally {
164	                setBusy(false);
165	              }
166	            }}
167	          >
168	            {busy ? 'Importing...' : 'Start Import'}
169	          </button>
170	          {error ? <p className="error">{error}</p> : null}
171	        </>
172	      ) : null}
173	
174	      <h2>Import History</h2>
175	      <table className="table">
176	        <thead>
177	          <tr>
178	            <th>Date</th>
179	            <th>Type</th>
180	            <th>Status</th>
181	            <th>Rows</th>
182	            <th>Duplicates</th>
183	            <th>Errors</th>
184	          </tr>
185	        </thead>
186	        <tbody>
187	          {(history ?? []).map((row) => (
188	            <tr key={row.id}>
189	              <td>{new Date(row.createdAt).toLocaleString()}</td>
190	              <td>{row.type ?? '-'}</td>
191	              <td>{row.status}</td>
192	              <td>{row.totalRows ?? '-'}</td>
193	              <td>{row.duplicateRows ?? '-'}</td>
194	              <td>{row.errorSummary ?? '-'}</td>
195	            </tr>
196	          ))}
197	        </tbody>
198	      </table>
199	      {(history ?? []).length === 0 && <p className="muted">No import history yet.</p>}
200	    </section>
201	  );
202	}
