1	import * as XLSX from 'xlsx';
2	import { db } from '../db/db';
3	import type { ImportBatch, ImportRow, User } from '../types';
4	import { auditService } from './auditService';
5	import { cryptoService } from './cryptoService';
6	import { notificationService } from './notificationService';
7	import { assertManagerOrAdmin } from './rbacService';
8	import { siteConfigService } from './siteConfigService';
9	
10	export type ImportType = 'reservations' | 'orders' | 'sessions';
11	export type FieldMap = Record<string, string>;
12	
13	const REQUIRED_FIELDS: Record<ImportType, string[]> = {
14	  reservations: [
15	    'stationId',
16	    'connectorId',
17	    'customerName',
18	    'customerPlate',
19	    'scheduledStart',
20	    'scheduledEnd'
21	  ],
22	  orders: [
23	    'orderNumber',
24	    'sessionId',
25	    'durationMinutes',
26	    'ratePerMinute',
27	    'adjustmentAmount',
28	    'adjustmentReason',
29	    'invoiceNotes'
30	  ],
31	  sessions: ['reservationId', 'startedAt']
32	};
33	
34	const TEMPLATE_ROWS: Record<ImportType, { headers: string[]; sample: string[] }> = {
35	  reservations: {
36	    headers: [
37	      'stationId',
38	      'connectorId',
39	      'customerName',
40	      'customerPlate',
41	      'scheduledStart',
42	      'scheduledEnd'
43	    ],
44	    sample: ['ST-01', 'C1', 'Alex Doe', 'ABC123', '04/01/2026 09:30', '04/01/2026 11:00']
45	  },
46	  orders: {
47	    headers: [
48	      'orderNumber',
49	      'sessionId',
50	      'durationMinutes',
51	      'ratePerMinute',
52	      'adjustmentAmount',
53	      'adjustmentReason',
54	      'invoiceNotes'
55	    ],
56	    sample: ['CB-SITE-001-20260401-0001', '100', '90', '0.5', '0', '', 'Imported invoice note']
57	  },
58	  sessions: {
59	    headers: ['reservationId', 'startedAt'],
60	    sample: ['100', '04/01/2026 09:30']
61	  }
62	};
63	
64	/**
65	 * RFC 4180-oriented parser for the import workflows.
66	 * Handles quoted fields, embedded commas, doubled-quote escapes (""),
67	 * and embedded newlines inside quoted cells.
68	 */
69	function parseCsv(csv: string): { headers: string[]; rows: Record<string, string>[] } {
70	  const records: string[][] = [];
71	  let row: string[] = [];
72	  let cell = '';
73	  let inQuotes = false;
74	
75	  for (let index = 0; index < csv.length; index += 1) {
76	    const ch = csv[index];
77	
78	    if (inQuotes) {
79	      if (ch === '"') {
80	        if (csv[index + 1] === '"') {
81	          cell += '"';
82	          index += 1;
83	        } else {
84	          inQuotes = false;
85	        }
86	      } else {
87	        cell += ch;
88	      }
89	      continue;
90	    }
91	
92	    if (ch === '"') {
93	      inQuotes = true;
94	      continue;
95	    }
96	
97	    if (ch === ',') {
98	      row.push(cell.trim());
99	      cell = '';
100	      continue;
101	    }
102	
103	    if (ch === '\n') {
104	      row.push(cell.trim());
105	      if (row.some((entry) => entry.length > 0)) {
106	        records.push(row);
107	      }
108	      row = [];
109	      cell = '';
110	      continue;
111	    }
112	
113	    if (ch !== '\r') {
114	      cell += ch;
115	    }
116	  }
117	
118	  row.push(cell.trim());
119	  if (row.some((entry) => entry.length > 0)) {
120	    records.push(row);
121	  }
122	
123	  if (records.length === 0) {
124	    return { headers: [], rows: [] };
125	  }
126	
127	  const [headers, ...dataRows] = records;
128	  const rows = dataRows.map((cells) => {
129	    const parsedRow: Record<string, string> = {};
130	    headers.forEach((header, index) => {
131	      parsedRow[header] = (cells[index] ?? '').trim();
132	    });
133	    return parsedRow;
134	  });
135	
136	  return { headers, rows };
137	}
138	
139	export function parseDate(value: string): number | null {
140	  // Full datetime format: MM/DD/YYYY HH:mm
141	  const fullMatch = value.match(/^(\d{2})\/(\d{2})\/(\d{4})\s(\d{2}):(\d{2})$/);
142	  if (fullMatch) {
143	    const [, mm, dd, yyyy, hh, min] = fullMatch;
144	    const month = Number(mm);
145	    const day = Number(dd);
146	    if (month < 1 || month > 12 || day < 1 || day > 31) return null;
147	    const date = new Date(Number(yyyy), month - 1, day, Number(hh), Number(min));
148	    return Number.isNaN(date.getTime()) ? null : date.getTime();
149	  }
150	  // Date-only format: MM/DD/YYYY — defaults to 00:00 local time
151	  const dateMatch = value.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
152	  if (dateMatch) {
153	    const [, mm, dd, yyyy] = dateMatch;
154	    const month = Number(mm);
155	    const day = Number(dd);
156	    if (month < 1 || month > 12 || day < 1 || day > 31) return null;
157	    const date = new Date(Number(yyyy), month - 1, day, 0, 0);
158	    return Number.isNaN(date.getTime()) ? null : date.getTime();
159	  }
160	  return null;
161	}
162	
163	async function sha256(text: string): Promise<string> {
164	  const buffer = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(text));
165	  return [...new Uint8Array(buffer)].map((b) => b.toString(16).padStart(2, '0')).join('');
166	}
167	
168	async function parseFile(file: File): Promise<{ headers: string[]; rows: Record<string, string>[]; raw: string }> {
169	  const readAsText =
170	    'text' in file
171	      ? async () => (await (file as unknown as { text: () => Promise<string> }).text())
172	      : async () =>
173	          await new Promise<string>((resolve, reject) => {
174	            const reader = new FileReader();
175	            reader.onload = () => resolve(String(reader.result ?? ''));
176	            reader.onerror = () => reject(reader.error);
177	            reader.readAsText(file);
178	          });
179	
180	  const readAsArrayBuffer =
181	    'arrayBuffer' in file
182	      ? async () =>
183	          await (file as unknown as { arrayBuffer: () => Promise<ArrayBuffer> }).arrayBuffer()
184	      : async () =>
185	          await new Promise<ArrayBuffer>((resolve, reject) => {
186	            const reader = new FileReader();
187	            reader.onload = () => resolve(reader.result as ArrayBuffer);
188	            reader.onerror = () => reject(reader.error);
189	            reader.readAsArrayBuffer(file);
190	          });
191	
192	  if (file.name.toLowerCase().endsWith('.xlsx')) {
193	    const bytes = await readAsArrayBuffer();
194	    const workbook = XLSX.read(bytes, { type: 'array' });
195	    const sheet = workbook.Sheets[workbook.SheetNames[0]];
196	    const matrix = XLSX.utils.sheet_to_json<(string | number)[]>(sheet, { header: 1 });
197	    const [headersRow = [], ...body] = matrix;
198	    const headers = headersRow.map((cell) => String(cell).trim());
199	    const rows = body.map((cells) => {
200	      const row: Record<string, string> = {};
201	      headers.forEach((header, index) => {
202	        row[header] = String(cells[index] ?? '').trim();
203	      });
204	      return row;
205	    });
206	    return { headers, rows, raw: JSON.stringify(matrix) };
207	  }
208	
209	  const text = await readAsText();
210	  const parsed = parseCsv(text);
211	  return { ...parsed, raw: text };
212	}
213	
214	function applyFieldMap(row: Record<string, string>, fieldMap: FieldMap): Record<string, string> {
215	  const mapped: Record<string, string> = {};
216	  Object.entries(fieldMap).forEach(([source, target]) => {
217	    if (target) {
218	      mapped[target] = row[source] ?? '';
219	    }
220	  });
221	  return mapped;
222	}
223	
224	async function validateRows(
225	  rows: Record<string, string>[],
226	  type: ImportType,
227	  actor: User
228	): Promise<{ importRows: ImportRow[]; invalidCount: number; validCount: number }> {
229	  const output: ImportRow[] = [];
230	  let invalidCount = 0;
231	  let validCount = 0;
232	
233	  for (let index = 0; index < rows.length; index += 1) {
234	    const row = rows[index];
235	    let errorCode: string | undefined;
236	
237	    for (const field of REQUIRED_FIELDS[type]) {
238	      if (!row[field]) {
239	        errorCode = 'IMPORT_REQUIRED_FIELD_MISSING';
240	      }
241	    }
242	
243	    if (!errorCode && type === 'reservations') {
244	      const start = parseDate(row.scheduledStart);
245	      const end = parseDate(row.scheduledEnd);
246	      if (!start || !end) {
247	        errorCode = 'IMPORT_DATE_FORMAT_INVALID';
248	      } else if (start >= end) {
249	        errorCode = 'IMPORT_DATE_RANGE_INVALID';
250	      } else {
251	        const bay = await db.bays
252	          .where('siteId')
253	          .equals(actor.siteId as number)
254	          .filter((b) => b.stationId === row.stationId && b.connectorId === row.connectorId)
255	          .first();
256	        if (!bay) {
257	          errorCode = 'IMPORT_BAY_NOT_FOUND';
258	        }
259	      }
260	    }
261	
262	    if (!errorCode && type === 'orders') {
263	      const duration = Number(row.durationMinutes);
264	      const rate = Number(row.ratePerMinute);
265	      const adjustment = Number(row.adjustmentAmount);
266	      // Pricing bounds per prompt spec: price must be $0.01–$9,999.99
267	      const RATE_MIN = 0.01;
268	      const RATE_MAX = 9999.99;
269	      if (!(duration > 0)) {
270	        errorCode = 'IMPORT_DURATION_INVALID';
271	      } else if (!(rate >= RATE_MIN) || !(rate <= RATE_MAX) || Number(rate.toFixed(2)) !== rate) {
272	        errorCode = 'IMPORT_RATE_OUT_OF_BOUNDS';
273	      } else if (Number.isNaN(adjustment)) {
274	        errorCode = 'IMPORT_ADJUSTMENT_INVALID';
275	      }
276	    }
277	
278	    output.push({
279	      batchId: 0,
280	      rowIndex: index + 1,
281	      status: errorCode ? 'Invalid' : 'Valid',
282	      rawData: JSON.stringify(rows[index]),
283	      cleanedData: JSON.stringify(row),
284	      errorCode
285	    });
286	
287	    if (errorCode) {
288	      invalidCount += 1;
289	    } else {
290	      validCount += 1;
291	    }
292	  }
293	
294	  return { importRows: output, invalidCount, validCount };
295	}
296	
297	function autoMapFields(headers: string[], type: ImportType): FieldMap {
298	  const required = REQUIRED_FIELDS[type];
299	  const lowerMap = new Map(required.map((field) => [field.toLowerCase(), field]));
300	  const map: FieldMap = {};
301	  headers.forEach((header) => {
302	    const target = lowerMap.get(header.toLowerCase());
303	    map[header] = target ?? '';
304	  });
305	  return map;
306	}
307	
308	function generateCsv(rows: string[][]): string {
309	  return rows.map((line) => line.join(',')).join('\n');
310	}
311	
312	function downloadTemplate(type: ImportType): void {
313	  const def = TEMPLATE_ROWS[type];
314	  const csv = generateCsv([def.headers, def.sample]);
315	  const blob = new Blob([csv], { type: 'text/csv' });
316	  const url = URL.createObjectURL(blob);
317	  const a = document.createElement('a');
318	  a.href = url;
319	  a.download = `${type}_template.csv`;
320	  a.click();
321	  URL.revokeObjectURL(url);
322	}
323	
324	async function validateFile(
325	  file: File,
326	  type: ImportType,
327	  fieldMap: FieldMap,
328	  actor: User
329	): Promise<{ totalRows: number; validRows: number; invalidRows: number; rows: ImportRow[]; headers: string[] }> {
330	  const parsed = await parseFile(file);
331	  const mappedRows = parsed.rows.map((row) => applyFieldMap(row, fieldMap));
332	  const validated = await validateRows(mappedRows, type, actor);
333	  return {
334	    totalRows: mappedRows.length,
335	    validRows: validated.validCount,
336	    invalidRows: validated.invalidCount,
337	    rows: validated.importRows,
338	    headers: parsed.headers
339	  };
340	}
341	
342	async function startImport(
343	  file: File,
344	  type: ImportType,
345	  fieldMap: FieldMap,
346	  actor: User,
347	  encryptionKey?: CryptoKey
348	): Promise<ImportBatch> {
349	  assertManagerOrAdmin(actor);
350	
351	  if (type !== 'sessions' && !encryptionKey) {
352	    throw new Error('IMPORT_ENCRYPTION_KEY_REQUIRED');
353	  }
354	
355	  const parsed = await parseFile(file);
356	  const dedupeHash = await sha256(parsed.raw);
357	
358	  const existingBatch = await db.importBatches
359	    .where('siteId')
360	    .equals(actor.siteId as number)
361	    .filter((b) => b.dedupeHash === dedupeHash)
362	    .first();
