16	    { siteId, stationId: 'ST-02', connectorId: 'C1', label: 'Bay 2', status: 'Available' }
17	  ]);
18	  const hash = await cryptoService.hashPassword('ChargeBay#Admin1');
19	  const userId = await db.users.add({
20	    username: 'sysadmin',
21	    passwordHash: hash.hash,
22	    salt: hash.salt,
23	    role: 'SystemAdministrator',
24	    siteId,
25	    failedAttempts: 0
26	  });
27	  const actor = (await db.users.get(userId))!;
28	  const encryptionKey = await cryptoService.deriveEncryptionKey('ChargeBay#Admin1', actor.salt);
29	  return { siteId, actor, encryptionKey };
30	}
