32	describe('importService — dedupe, validation, and rollback', () => {
33	  beforeEach(async () => {
34	    localStorage.clear();
35	    await resetDb();
36	  });
37	
38	  // D — Import rollback proof: mixed-validity payload inserts zero rows
39	  it('rejects entire batch when any row is invalid (rollback semantics)', async () => {
40	    const { actor, encryptionKey } = await setup();
41	    const csv = [
42	      'stationId,connectorId,customerName,customerPlate,scheduledStart,scheduledEnd',
43	      'ST-01,C1,Good Row,ABC123,04/01/2026 09:30,04/01/2026 11:00',
44	      'ST-02,C1,Bad Date,XYZ999,BAD_DATE,04/01/2026 12:00'
45	    ].join('\n');
46	    const file = new File([csv], 'mixed.csv', { type: 'text/csv' });
47	    const map = importService.autoMapFields(
48	      ['stationId', 'connectorId', 'customerName', 'customerPlate', 'scheduledStart', 'scheduledEnd'],
49	      'reservations'
50	    );
51	
52	    const batch = await importService.startImport(file, 'reservations', map, actor, encryptionKey);
53	    expect(batch.status).toBe('Failed');
54	    expect(batch.invalidRows).toBeGreaterThan(0);
55	
56	    // Zero partial inserts — rollback semantics
57	    const reservationCount = await db.reservations.count();
58	    expect(reservationCount).toBe(0);
59	  });
60	
61	  it('batch status is Failed and error rows are recorded', async () => {
62	    const { actor, encryptionKey } = await setup();
63	    const csv = [
64	      'stationId,connectorId,customerName,customerPlate,scheduledStart,scheduledEnd',
65	      'ST-01,C1,,ABC123,04/01/2026 09:30,04/01/2026 11:00'
66	    ].join('\n');
