75	    const rows = await db.importRows.where('batchId').equals(batch.id as number).toArray();
76	    expect(rows.some(r => r.errorCode === 'IMPORT_REQUIRED_FIELD_MISSING')).toBe(true);
77	  });
78	
79	  // Dedupe: duplicate file hash is rejected
80	  it('duplicate file hash throws IMPORT_DUPLICATE_FILE', async () => {
81	    const { actor, encryptionKey } = await setup();
