87	    const map = importService.autoMapFields(
88	      ['stationId', 'connectorId', 'customerName', 'customerPlate', 'scheduledStart', 'scheduledEnd'],
89	      'reservations'
90	    );
91	
92	    await importService.startImport(file, 'reservations', map, actor, encryptionKey);
93	    await expect(
94	      importService.startImport(file, 'reservations', map, actor, encryptionKey)
95	    ).rejects.toThrow('IMPORT_DUPLICATE_FILE');
96	  });
