214	function applyFieldMap(row: Record<string, string>, fieldMap: FieldMap): Record<string, string> {
215	  const mapped: Record<string, string> = {};
216	  Object.entries(fieldMap).forEach(([source, target]) => {
217	    if (target) {
218	      mapped[target] = row[source] ?? '';
219	    }
220	  });
221	  return mapped;
222	}
223	
224	async function validateRows(
225	  rows: Record<string, string>[],
226	  type: ImportType,
227	  targetSiteId: number
228	): Promise<{ importRows: ImportRow[]; invalidCount: number; validCount: number }> {
229	  const output: ImportRow[] = [];
230	  let invalidCount = 0;
231	  let validCount = 0;
232	
233	  for (let index = 0; index < rows.length; index += 1) {
234	    const row = rows[index];
235	    let errorCode: string | undefined;
236	
237	    for (const field of REQUIRED_FIELDS[type]) {
238	      if (!row[field]) {
239	        errorCode = 'IMPORT_REQUIRED_FIELD_MISSING';
240	      }
241	    }
242	
243	    if (!errorCode && type === 'reservations') {
244	      const start = parseDate(row.scheduledStart);
245	      const end = parseDate(row.scheduledEnd);
246	      if (!start || !end) {
247	        errorCode = 'IMPORT_DATE_FORMAT_INVALID';
248	      } else if (start >= end) {
249	        errorCode = 'IMPORT_DATE_RANGE_INVALID';
250	      } else {
251	        const bay = await db.bays
252	          .where('siteId')
253	          .equals(targetSiteId)
254	          .filter((b) => b.stationId === row.stationId && b.connectorId === row.connectorId)
255	          .first();
256	        if (!bay) {
257	          errorCode = 'IMPORT_BAY_NOT_FOUND';
258	        }
259	      }
260	    }
261	
262	    if (!errorCode && type === 'orders') {
263	      const duration = Number(row.durationMinutes);
264	      const rate = Number(row.ratePerMinute);
265	      const adjustment = Number(row.adjustmentAmount);
266	      // Pricing bounds per prompt spec: price must be $0.01–$9,999.99
267	      const RATE_MIN = 0.01;
268	      const RATE_MAX = 9999.99;
269	      if (!(duration > 0)) {
270	        errorCode = 'IMPORT_DURATION_INVALID';
271	      } else if (!(rate >= RATE_MIN) || !(rate <= RATE_MAX) || Number(rate.toFixed(2)) !== rate) {
272	        errorCode = 'IMPORT_RATE_OUT_OF_BOUNDS';
273	      } else if (Number.isNaN(adjustment)) {
274	        errorCode = 'IMPORT_ADJUSTMENT_INVALID';
275	      }
276	    }
277	
278	    output.push({
279	      batchId: 0,
280	      rowIndex: index + 1,
281	      status: errorCode ? 'Invalid' : 'Valid',
282	      rawData: JSON.stringify(rows[index]),
283	      cleanedData: JSON.stringify(row),
284	      errorCode
285	    });
286	
287	    if (errorCode) {
288	      invalidCount += 1;
289	    } else {
290	      validCount += 1;
291	    }
292	  }
293	
294	  return { importRows: output, invalidCount, validCount };
295	}
