312	function downloadTemplate(type: ImportType): void {
313	  const def = TEMPLATE_ROWS[type];
314	  const csv = generateCsv([def.headers, def.sample]);
315	  const blob = new Blob([csv], { type: 'text/csv' });
316	  const url = URL.createObjectURL(blob);
317	  const a = document.createElement('a');
318	  a.href = url;
319	  a.download = `${type}_template.csv`;
320	  a.click();
321	  URL.revokeObjectURL(url);
322	}
323	
324	async function validateFile(
325	  file: File,
326	  type: ImportType,
327	  fieldMap: FieldMap,
328	  targetSiteId: number
329	): Promise<{ totalRows: number; validRows: number; invalidRows: number; rows: ImportRow[]; headers: string[] }> {
330	  const parsed = await parseFile(file);
331	  const mappedRows = parsed.rows.map((row) => applyFieldMap(row, fieldMap));
332	  const validated = await validateRows(mappedRows, type, targetSiteId);
333	  return {
334	    totalRows: mappedRows.length,
335	    validRows: validated.validCount,
336	    invalidRows: validated.invalidCount,
337	    rows: validated.importRows,
338	    headers: parsed.headers
339	  };
340	}
