342	async function startImport(
343	  file: File,
344	  type: ImportType,
345	  fieldMap: FieldMap,
346	  actor: User,
347	  targetSiteId: number,
348	  encryptionKey?: CryptoKey
349	): Promise<ImportBatch> {
350	  assertManagerOrAdmin(actor);
351	
352	  if (type !== 'sessions' && !encryptionKey) {
353	    throw new Error('IMPORT_ENCRYPTION_KEY_REQUIRED');
354	  }
355	
356	  const parsed = await parseFile(file);
357	  const dedupeHash = await sha256(parsed.raw);
358	
359	  const existingBatch = await db.importBatches
360	    .where('siteId')
361	    .equals(targetSiteId)
362	    .filter((b) => b.dedupeHash === dedupeHash)
363	    .first();
364	  if (existingBatch) {
365	    throw new Error('IMPORT_DUPLICATE_FILE');
366	  }
367	
368	  const batchId = await db.importBatches.add({
369	    siteId: targetSiteId,
370	    type,
371	    status: 'Validating',
372	    createdAt: Date.now(),
373	    dedupeHash
374	  });
375	
376	  const mappedRows = parsed.rows.map((row) => applyFieldMap(row, fieldMap));
377	  const validation = await validateRows(mappedRows, type, targetSiteId);
378	  const validationRows = validation.importRows.map((row) => ({ ...row, batchId }));
379	  await db.importRows.bulkAdd(validationRows);
380	
381	  if (validation.invalidCount > 0) {
382	    await db.importBatches.update(batchId, {
383	      status: 'Failed',
384	      totalRows: mappedRows.length,
385	      validRows: validation.validCount,
386	      invalidRows: validation.invalidCount,
387	      duplicateRows: 0,
388	      errorSummary: `${validation.invalidCount} invalid rows`
389	    });
390	    await notificationService.send(actor.id as number, 'IMPORT_FAILED', {
391	      batchId: String(batchId),
392	      reason: `${validation.invalidCount} validation errors`
393	    });
394	    return (await db.importBatches.get(batchId)) as ImportBatch;
395	  }
396	
397	  // Pre-encrypt sensitive fields outside the Dexie transaction
398	  // (WebCrypto operations break IndexedDB transaction scope)
399	  const encryptedRows: Array<{ encName?: string; encPlate?: string; encNotes?: string }> = [];
400	  if (type === 'reservations' || type === 'orders') {
401	    for (const row of mappedRows) {
402	      if (type === 'reservations') {
403	        encryptedRows.push({
404	          encName: await cryptoService.encryptField(row.customerName, encryptionKey!),
405	          encPlate: await cryptoService.encryptField(row.customerPlate, encryptionKey!)
406	        });
407	      } else {
408	        encryptedRows.push({
409	          encNotes: await cryptoService.encryptField(row.invoiceNotes, encryptionKey!)
410	        });
411	      }
412	    }
413	  }
414	
415	  let duplicateRows = 0;
416	  await db.transaction(
417	    'rw',
418	    db.reservations,
419	    db.orders,
420	    db.sessions_charging,
421	    db.bays,
422	    db.importRows,
423	    async () => {
424	      for (let index = 0; index < mappedRows.length; index += 1) {
425	        const row = mappedRows[index];
426	        let isDuplicate = false;
427	
428	        if (type === 'reservations') {
429	          const start = parseDate(row.scheduledStart) as number;
430	          const bay = await db.bays
431	            .where('siteId')
432	            .equals(targetSiteId)
433	            .filter((b) => b.stationId === row.stationId && b.connectorId === row.connectorId)
434	            .first();
435	
436	          const dup = await db.reservations
437	            .where('siteId')
438	            .equals(targetSiteId)
439	            .filter((r) => r.bayId === bay?.id && r.scheduledStart === start)
440	            .first();
441	          if (dup) {
442	            isDuplicate = true;
443	          } else {
444	            const encName = encryptedRows[index]!.encName!;
445	            const encPlate = encryptedRows[index]!.encPlate!;
446	            await db.reservations.add({
447	              operationId: crypto.randomUUID(),
448	              bayId: bay?.id as number,
449	              siteId: targetSiteId,
450	              userId: actor.id as number,
451	              customerName: encName,
452	              customerPlate: encPlate,
453	              scheduledStart: start,
454	              scheduledEnd: parseDate(row.scheduledEnd) as number,
455	              status: 'Scheduled',
456	              noShowDeadline: start + siteConfigService.getSiteConfig(targetSiteId).noShowGraceMinutes * 60_000,
457	              version: 1,
458	              importBatchId: batchId,
459	              importRowId: index + 1
460	            });
461	          }
462	        }
463	
464	        if (type === 'orders') {
465	          const dup = await db.orders
466	            .where('siteId')
467	            .equals(targetSiteId)
468	            .filter((o) => o.orderNumber === row.orderNumber)
469	            .first();
470	          if (dup) {
471	            isDuplicate = true;
472	          } else {
473	            const duration = Number(row.durationMinutes);
474	            const rate = Number(row.ratePerMinute);
475	            const adjustment = Number(row.adjustmentAmount);
476	            const subtotal = Number((duration * rate).toFixed(2));
477	            const encNotes = encryptedRows[index]!.encNotes!;
478	            await db.orders.add({
479	              operationId: crypto.randomUUID(),
480	              sessionId: Number(row.sessionId),
481	              siteId: targetSiteId,
482	              orderNumber: row.orderNumber,
483	              status: 'Draft',
484	              billingType: 'Standard',
485	              durationMinutes: duration,
486	              ratePerMinute: rate,
487	              subtotal,
488	              adjustmentAmount: adjustment,
489	              adjustmentReason: row.adjustmentReason,
490	              totalAmount: Number((subtotal + adjustment).toFixed(2)),
491	              invoiceNotes: encNotes,
492	              reconciliationStatus: 'Unreconciled',
493	              version: 1,
494	              importBatchId: batchId,
495	              importRowId: index + 1
496	            });
497	          }
498	        }
499	
500	        if (type === 'sessions') {
501	          const startedAt = parseDate(row.startedAt);
502	          const dup = await db.sessions_charging
503	            .where('reservationId')
504	            .equals(Number(row.reservationId))
505	            .filter((s) => s.startedAt === startedAt)
506	            .first();
507	          if (dup) {
508	            isDuplicate = true;
509	          } else {
510	            const reservation = await db.reservations.get(Number(row.reservationId));
511	            if (reservation) {
512	              await db.sessions_charging.add({
513	                reservationId: reservation.id as number,
514	                bayId: reservation.bayId,
515	                siteId: reservation.siteId,
516	                startedAt: startedAt as number,
517	                status: 'Active',
518	                heartbeatAt: startedAt as number,
519	                tempLeaveCount: 0,
520	                version: 1,
521	                importBatchId: batchId,
522	                importRowId: index + 1
523	              });
524	            }
525	          }
526	        }
527	
528	        if (isDuplicate) {
529	          duplicateRows += 1;
530	          const row = await db.importRows
531	            .where('batchId')
532	            .equals(batchId)
533	            .filter((item) => item.rowIndex === index + 1)
534	            .first();
535	          if (row?.id) {
536	            await db.importRows.update(row.id, { status: 'Duplicate' });
537	          }
538	        } else {
539	          const row = await db.importRows
540	            .where('batchId')
541	            .equals(batchId)
542	            .filter((item) => item.rowIndex === index + 1)
543	            .first();
544	          if (row?.id) {
545	            await db.importRows.update(row.id, { status: 'Imported' });
546	          }
547	        }
548	      }
549	    }
550	  );
551	
552	  await db.importBatches.update(batchId, {
553	    status: 'Complete',
554	    totalRows: mappedRows.length,
555	    validRows: validation.validCount,
556	    invalidRows: validation.invalidCount,
557	    duplicateRows
558	  });
559	
560	  await notificationService.send(actor.id as number, 'IMPORT_COMPLETE', {
561	    rowCount: String(mappedRows.length - duplicateRows)
562	  });
563	  await auditService.log(actor, 'IMPORT_COMPLETED', 'ImportBatch', batchId, {
564	    type,
565	    totalRows: mappedRows.length,
566	    duplicateRows
567	  });
568	
569	  return (await db.importBatches.get(batchId)) as ImportBatch;
570	}
