1	import { db } from '../db/db';
2	import type { StoredSession, User } from '../types';
3	import { cryptoService } from './cryptoService';
4	import { auditService } from './auditService';
5	
6	export const AUTH_SESSION_KEY = 'cb_session';
7	const LOCKOUT_THRESHOLD = 5;
8	const LOCKOUT_DURATION_MS = 15 * 60 * 1000;
9	const SESSION_DURATION_MS = 8 * 60 * 60 * 1000;
10	
11	export class AuthWrongPasswordError extends Error {
12	  code = 'AUTH_WRONG_PASSWORD' as const;
13	
14	  constructor() {
15	    super('AUTH_WRONG_PASSWORD');
16	    this.name = 'AuthWrongPasswordError';
17	  }
18	}
19	
20	export class AuthLockedError extends Error {
21	  code = 'AUTH_LOCKED' as const;
22	  remainingMs: number;
23	
24	  constructor(remainingMs: number) {
25	    super('AUTH_LOCKED');
26	    this.name = 'AuthLockedError';
27	    this.remainingMs = remainingMs;
28	  }
29	}
30	
31	function storeSession(session: StoredSession) {
32	  localStorage.setItem(AUTH_SESSION_KEY, JSON.stringify(session));
33	}
34	
35	function getStoredSession(): StoredSession | null {
36	  const raw = localStorage.getItem(AUTH_SESSION_KEY);
37	  if (!raw) {
38	    return null;
39	  }
40	
41	  try {
42	    return JSON.parse(raw) as StoredSession;
43	  } catch {
44	    localStorage.removeItem(AUTH_SESSION_KEY);
45	    return null;
46	  }
47	}
48	
49	async function login(
50	  username: string,
51	  password: string
52	): Promise<{ user: User; encryptionKey: CryptoKey }> {
53	  const user = await db.users.where('username').equals(username).first();
54	  if (!user) {
55	    throw new AuthWrongPasswordError();
56	  }
57	
58	  const now = Date.now();
59	  if (user.lockedUntil && user.lockedUntil > now) {
60	    throw new AuthLockedError(user.lockedUntil - now);
61	  }
62	
63	  const isValid = await cryptoService.verifyPassword(password, user.passwordHash, user.salt);
64	  if (!isValid) {
65	    const nextAttempts = user.failedAttempts + 1;
66	    if (nextAttempts >= LOCKOUT_THRESHOLD) {
67	      const lockedUntil = now + LOCKOUT_DURATION_MS;
68	      await db.users.update(user.id as number, { failedAttempts: 0, lockedUntil });
69	      await auditService.log(user, 'AUTH_ACCOUNT_LOCKED', 'User', user.id as number, {
70	        lockedUntil
71	      });
72	      throw new AuthLockedError(LOCKOUT_DURATION_MS);
73	    }
74	
75	    await db.users.update(user.id as number, { failedAttempts: nextAttempts });
76	    await auditService.log(user, 'AUTH_FAILED_ATTEMPT', 'User', user.id as number, {
77	      failedAttempts: nextAttempts
78	    });
79	    throw new AuthWrongPasswordError();
80	  }
81	
82	  await db.users.update(user.id as number, { failedAttempts: 0, lockedUntil: undefined });
83	
84	  const sessionId = await db.sessions_auth.add({
85	    userId: user.id as number,
86	    createdAt: now,
87	    lastActiveAt: now
88	  });
89	
90	  storeSession({
91	    sessionId,
92	    userId: user.id as number,
93	    role: user.role,
94	    siteId: user.siteId
95	  });
96	
97	  const keySalt = user.salt;
98	  const encryptionKey = await cryptoService.deriveEncryptionKey(password, keySalt);
99	  await auditService.log(user, 'AUTH_LOGIN', 'User', user.id as number);
100	
101	  return {
102	    user: {
103	      ...user,
104	      failedAttempts: 0,
105	      lockedUntil: undefined
106	    },
107	    encryptionKey
108	  };
109	}
110	
111	function logout() {
112	  localStorage.removeItem(AUTH_SESSION_KEY);
113	}
114	
115	async function restoreSession(): Promise<User | null> {
116	  const stored = getStoredSession();
117	  if (!stored) {
118	    return null;
119	  }
120	
121	  const session = await db.sessions_auth.get(stored.sessionId);
122	  if (!session) {
123	    localStorage.removeItem(AUTH_SESSION_KEY);
124	    return null;
125	  }
126	
127	  const now = Date.now();
128	  if (session.lastActiveAt < now - SESSION_DURATION_MS) {
129	    await db.sessions_auth.delete(session.id as number);
130	    localStorage.removeItem(AUTH_SESSION_KEY);
131	    return null;
132	  }
133	
134	  await db.sessions_auth.update(session.id as number, { lastActiveAt: now });
135	  const user = await db.users.get(stored.userId);
136	  if (!user) {
137	    localStorage.removeItem(AUTH_SESSION_KEY);
138	    return null;
139	  }
140	
141	  await auditService.log(user, 'AUTH_SESSION_RESTORED', 'SessionAuth', session.id as number);
142	
143	  return user;
144	}
145	
146	export const authService = {
147	  login,
148	  logout,
149	  restoreSession
150	};
