12	/**
13	 * Package format for offline device-to-device transfer.
14	 * `signature` is a password-bound integrity check: SHA-256(plaintext_payload + password).
15	 * This provides tamper-detection tied to the export password; it is NOT an
16	 * asymmetric cryptographic signature and does not establish signer identity.
17	 * The `ciphertext` is the AES-GCM encrypted payload derived from the same password.
18	 */
19	interface ExportPackage {
20	  version: 1;
21	  siteId: number;
22	  exportedAt: number;
23	  exportedBy: string;
24	  dateRange: DateRange;
25	  /** Password-bound integrity hash: SHA-256(payload + password). */
26	  signature: string;
27	  salt: string;
28	  iv: string;
29	  ciphertext: string;
30	}
31	
32	function bytesToHex(bytes: Uint8Array): string {
33	  return [...bytes].map((b) => b.toString(16).padStart(2, '0')).join('');
34	}
35	
36	function hexToBytes(hex: string): Uint8Array {
37	  const out = new Uint8Array(hex.length / 2);
38	  for (let index = 0; index < out.length; index += 1) {
39	    out[index] = Number.parseInt(hex.slice(index * 2, index * 2 + 2), 16);
40	  }
41	  return out;
42	}
43	
44	function bytesToBase64(bytes: Uint8Array): string {
45	  let binary = '';
46	  for (const byte of bytes) binary += String.fromCharCode(byte);
47	  return btoa(binary);
48	}
49	
50	function base64ToBytes(base64: string): Uint8Array {
51	  const binary = atob(base64);
52	  const out = new Uint8Array(binary.length);
53	  for (let i = 0; i < binary.length; i += 1) out[i] = binary.charCodeAt(i);
54	  return out;
55	}
56	
57	async function sha256Hex(value: string): Promise<string> {
58	  const digest = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(value));
59	  return bytesToHex(new Uint8Array(digest));
60	}
