70	  const [reservations, sessions, orders, reservationsCold, sessionsCold, ordersCold] = await Promise.all([
71	    db.reservations
72	      .where('siteId')
73	      .equals(siteId)
74	      .filter((r) => r.scheduledStart >= dateRange.from && r.scheduledStart <= dateRange.to)
75	      .toArray(),
76	    db.sessions_charging
77	      .where('siteId')
78	      .equals(siteId)
79	      .filter((s) => s.startedAt >= dateRange.from && s.startedAt <= dateRange.to)
80	      .toArray(),
81	    db.orders
82	      .where('siteId')
83	      .equals(siteId)
84	      .filter((o) => (o.createdAt ?? 0) >= dateRange.from && (o.createdAt ?? 0) <= dateRange.to)
85	      .toArray(),
86	    db.reservations_cold.where('siteId').equals(siteId).toArray(),
87	    db.sessions_cold.where('siteId').equals(siteId).toArray(),
88	    db.orders_cold.where('siteId').equals(siteId).toArray()
89	  ]);
90	
91	  const payload = JSON.stringify({
92	    reservations,
93	    sessions,
94	    orders,
95	    reservationsCold,
96	    sessionsCold,
97	    ordersCold
98	  });
99	  const signature = await sha256Hex(payload + password);
100	  const salt = bytesToHex(crypto.getRandomValues(new Uint8Array(16)));
101	  const key = await cryptoService.deriveEncryptionKey(password, salt);
102	  const iv = crypto.getRandomValues(new Uint8Array(12));
103	  const cipher = await crypto.subtle.encrypt(
104	    { name: 'AES-GCM', iv },
105	    key,
106	    new TextEncoder().encode(payload)
107	  );
108	
109	  const pkg: ExportPackage = {
110	    version: 1,
111	    siteId,
112	    exportedAt: Date.now(),
113	    exportedBy: actor.username,
114	    dateRange,
115	    signature,
116	    salt,
117	    iv: bytesToHex(iv),
118	    ciphertext: bytesToBase64(new Uint8Array(cipher))
119	  };
120	
121	  const json = JSON.stringify(pkg, null, 2);
122	  const blob = new Blob([json], { type: 'application/json' });
123	  const url = URL.createObjectURL(blob);
