12	/**
13	 * Package format for offline device-to-device transfer.
14	 * `signature` is a password-bound integrity check: SHA-256(plaintext_payload + password).
15	 * This provides tamper-detection tied to the export password; it is NOT an
16	 * asymmetric cryptographic signature and does not establish signer identity.
17	 * The `ciphertext` is the AES-GCM encrypted payload derived from the same password.
18	 */
19	interface ExportPackage {
20	  version: 1;
21	  siteId: number;
22	  exportedAt: number;
23	  exportedBy: string;
24	  dateRange: DateRange;
25	  /** Password-bound integrity hash: SHA-256(payload + password). */
26	  signature: string;
27	  salt: string;
28	  iv: string;
29	  ciphertext: string;
30	}
