73	      .equals(siteId)
74	      .filter((r) => r.scheduledStart >= dateRange.from && r.scheduledStart <= dateRange.to)
75	      .toArray(),
76	    db.sessions_charging
77	      .where('siteId')
78	      .equals(siteId)
79	      .filter((s) => s.startedAt >= dateRange.from && s.startedAt <= dateRange.to)
80	      .toArray(),
81	    db.orders
82	      .where('siteId')
83	      .equals(siteId)
84	      .filter((o) => (o.createdAt ?? 0) >= dateRange.from && (o.createdAt ?? 0) <= dateRange.to)
85	      .toArray(),
86	    db.reservations_cold.where('siteId').equals(siteId).toArray(),
87	    db.sessions_cold.where('siteId').equals(siteId).toArray(),
