172	      orders: Array<{ id?: number; siteId?: number }>;
173	      reservationsCold: Array<{ id?: number; siteId?: number }>;
174	      sessionsCold: Array<{ id?: number; siteId?: number }>;
175	      ordersCold: Array<{ id?: number; siteId?: number }>;
176	    };
